t.script:
(function () {
    const script = document.currentScript;
    const token = script.getAttribute('data-token');

    async function fetchDays() {
        const resp = await fetch('/my/pickup/' + token + '/slots', {
            method: 'POST',
            headers: {'Content-Type': 'application/json'},
            body: JSON.stringify({jsonrpc: '2.0', method: 'call', params: {}}),
        });
        const payload = await resp.json();
        return (payload && payload.result) || [];
    }

    function byState(days) {
        const open = new Set();
        const unavailable = new Set();
        days.forEach(function (d) {
            if (d.state === 'open') open.add(d.date);
            else unavailable.add(d.date);
        });
        return {open: open, unavailable: unavailable, all: days};
    }

    fetchDays().then(function (days) {
        const sets = byState(days);
        const first = days[0] ? days[0].date : null;
        const last = days[days.length - 1] ? days[days.length - 1].date : null;

        // --- Option A: native date input ---
        const nativeInput = document.getElementById('native-date-input');
        const nativeSubmit = document.getElementById('native-submit');
        const nativeStatus = document.getElementById('native-status');
        if (nativeInput && first && last) {
            nativeInput.min = first;
            nativeInput.max = last;
            nativeInput.addEventListener('change', function () {
                const v = nativeInput.value;
                if (!v) {
                    nativeSubmit.disabled = true;
                    nativeStatus.textContent = '';
                    return;
                }
                if (sets.open.has(v)) {
                    nativeSubmit.disabled = false;
                    nativeStatus.textContent = 'Jour disponible.';
                    nativeStatus.className = 'mt-2 small text-success';
                } else {
                    nativeSubmit.disabled = true;
                    nativeStatus.textContent = 'Ce jour est fermé ou complet. Choisissez un autre jour.';
                    nativeStatus.className = 'mt-2 small text-danger';
                }
            });
        }

        // --- Option B: Flatpickr ---
        const fpInput = document.getElementById('flatpickr-date-input');
        const fpSubmit = document.getElementById('flatpickr-submit');
        const fpStatus = document.getElementById('flatpickr-status');
        if (fpInput && window.flatpickr) {
            const disabledDates = Array.from(sets.unavailable);
            window.flatpickr(fpInput, {
                locale: (window.flatpickr.l10ns && window.flatpickr.l10ns.fr) || undefined,
                dateFormat: 'Y-m-d',
                altInput: true,
                altFormat: 'l j F Y',
                minDate: first,
                maxDate: last,
                disable: disabledDates,
                onChange: function (selectedDates, dateStr) {
                    if (dateStr) {
                        fpSubmit.disabled = false;
                        fpStatus.textContent = 'Jour sélectionné : ' + dateStr;
                        fpStatus.className = 'mt-2 small text-success';
                    } else {
                        fpSubmit.disabled = true;
                        fpStatus.textContent = '';
                    }
                },
            });
        }
    }).catch(function (e) {
        console.error(e);
    });
})();
